import { folders } from '~constants';
import { createTask } from '#gear:routines';

import type { CreateManifestContext } from '../context';

/**
 * ?
 */
export default createTask<CreateManifestContext>(
  async (context) =>
  {
    const { templates } = context;

    const result = [
      '// The content of this file is generated by the `templates/create-manifest` task.',
      'export const templates = {',
      ...templates.map(template => `'${ template.name }': '${ template.id }.ts',`),
      '};'
    ];

    await Bun.write(`${ folders.artifacts }/templates.ts`, result.join('\n'));
  }
);
